mapper.update:
UPDATE interview_session SET evaluate_status = #{evaluateStatus}, evaluate_error = #{evaluateError},
                             report_id = #{reportId}, evaluate_retry_count = #{evaluateRetryCount}
WHERE id = #{id}

mapper.select:
SELECT s.id, s.user_id, s.position, s.round, s.difficulty, s.question_count, s.max_follow_up, s.current_question, s.question_ids, s.resume_id, s.interview_type, s.status, s.evaluate_status, s.report_id, s.created_at, s.updated_at, r.total_score, r.level, r.created_at AS report_created_at FROM interview_session s LEFT JOIN interview_report r ON s.id = r.session_id WHERE s.user_id = #{userId}
AND s.status = #{status}
ORDER BY s.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM interview_session
WHERE user_id = #{userId}

    AND status = #{status}
